/// Build a scoped impl key from a self-type path and current inline-module path.
/// For local impls like `impl Foo` inside `mod a`, this returns `a::Foo`.
/// For explicit paths (`foo::Bar`), keep the path as-is.
/// For `self::` / `super::` / `crate::`, resolve to the current module stack.
fn qualify_impl_type_name(
    raw: &str,
    module_path: &[String],
    top_level_declared_item_names: &HashSet<String>,
) -> String {
    let parts: Vec<&str> = raw.split("::").collect();
    if parts.is_empty() {
        return raw.to_string();
    }

    if parts.len() == 1 {
        if module_path.is_empty() {
            return raw.to_string();
        }
        // If a nested module `impl` targets a top-level type imported from
        // `super`/`crate` (for example `use super::Either; impl Iterator for Either`),
        // keep the top-level name so methods merge into the real type definition.
        if top_level_declared_item_names.contains(raw) {
            return raw.to_string();
        }
        return format!("{}::{}", module_path.join("::"), raw);
    }

    let mut resolved_prefix = module_path.to_vec();
    let mut idx = 0usize;
    let mut had_relative_prefix = false;
    while idx < parts.len() {
        match parts[idx] {
            "self" => {
                had_relative_prefix = true;
                idx += 1;
            }
            "super" => {
                had_relative_prefix = true;
                if !resolved_prefix.is_empty() {
                    resolved_prefix.pop();
                }
                idx += 1;
            }
            "crate" => {
                had_relative_prefix = true;
                resolved_prefix.clear();
                idx += 1;
            }
            _ => break,
        }
    }

    if !had_relative_prefix {
        return raw.to_string();
    }

    let mut out = resolved_prefix;
    out.extend(parts[idx..].iter().map(|s| s.to_string()));
    if out.is_empty() {
        raw.to_string()
    } else {
        out.join("::")
    }
}

enum UseImportAction {
    RustOnly,
    Using(String),
    Raw(String),
}

fn classify_use_import(path: &str) -> UseImportAction {
    let normalized = normalize_use_import_path(path);
    if let Some((alias, target_path)) = split_use_import_alias(normalized) {
        return match classify_use_import(target_path) {
            UseImportAction::RustOnly => UseImportAction::RustOnly,
            UseImportAction::Using(mapped_target) => {
                if alias_target_requires_template_alias(&mapped_target) {
                    UseImportAction::Raw(format!(
                        "template<typename... Ts> using {} = {}<Ts...>;",
                        alias, mapped_target
                    ))
                } else {
                    UseImportAction::Using(format!("{} = {}", alias, mapped_target))
                }
            }
            UseImportAction::Raw(statement) => {
                if let Some(target) = parse_namespace_alias_target(&statement) {
                    UseImportAction::Raw(format!("namespace {} = {};", alias, target))
                } else {
                    UseImportAction::RustOnly
                }
            }
        };
    }

    if is_either_variant_reexport(normalized) {
        return UseImportAction::RustOnly;
    }
    if let Some(action) = rewrite_std_panic_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_ptr_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_mem_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_cell_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_marker_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_io_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_string_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_net_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_any_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_path_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_alloc_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_num_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_primitive_module_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_str_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_char_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_vec_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_collections_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_slice_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_option_import(normalized) {
        return action;
    }
    if let Some(action) = rewrite_std_cmp_import(normalized) {
        return action;
    }
    if is_rust_only_import(normalized) {
        return UseImportAction::RustOnly;
    }
    UseImportAction::Using(path.to_string())
}

fn normalize_use_import_path(path: &str) -> &str {
    path.strip_prefix("namespace ").unwrap_or(path)
}

fn split_use_import_alias(path: &str) -> Option<(&str, &str)> {
    let (alias, target) = path.split_once('=')?;
    let alias = alias.trim();
    let target = target.trim();
    if alias.is_empty() || target.is_empty() {
        return None;
    }
    Some((alias, target))
}

fn parse_namespace_alias_target(statement: &str) -> Option<&str> {
    let trimmed = statement.trim().strip_suffix(';')?;
    let rest = trimmed.strip_prefix("namespace ")?;
    let (_, target) = rest.split_once('=')?;
    let target = target.trim();
    if target.is_empty() {
        return None;
    }
    Some(target)
}

fn alias_target_requires_template_alias(target: &str) -> bool {
    target == "rusty::Option"
}

/// C++ `using` declarations require either a nested-name-specifier (`a::b`) or alias
/// form (`X = Y`). Rust `use super::{Foo}` can flatten to bare names, so normalize
/// those to global-qualified form.
fn make_using_path_cpp_legal(path: &str) -> String {
    if path.is_empty() || path.starts_with("namespace ") {
        return path.to_string();
    }

    if let Some((alias, target)) = split_use_import_alias(path) {
        let alias = escape_cpp_keyword(alias);
        let target = escape_cpp_path_segments(target);
        return format!("{} = {}", alias, target);
    }

    if path.starts_with("::") {
        return format!(
            "::{}",
            escape_cpp_path_segments(path.trim_start_matches("::"))
        );
    }

    if path.contains("::") {
        return escape_cpp_path_segments(path);
    }

    format!("::{}", escape_cpp_keyword(path))
}

fn escape_cpp_path_segments(path: &str) -> String {
    path.split("::")
        .map(escape_cpp_keyword)
        .collect::<Vec<_>>()
        .join("::")
}

/// `pub use ...::Either::{Left, Right};` often appears before the enum declaration in the
/// source order. Emitting a C++ `using` for these names at that point is invalid because
/// `Either` is not yet declared, so treat these as Rust-only imports for now.
fn is_either_variant_reexport(path: &str) -> bool {
    let parts: Vec<&str> = path.split("::").collect();
    if parts.len() < 2 {
        return false;
    }

    let enum_name = parts[parts.len() - 2];
    let variant_name = parts[parts.len() - 1];
    enum_name == "Either" && matches!(variant_name, "Left" | "Right")
}

/// Some pub re-exports in module mode refer to declarations with module linkage
/// (for example `pub use iterator::IterEither;` in expanded either output).
/// Emitting `export using` for these names is rejected by compilers, so keep
/// them as Rust-only until the originating declaration is explicitly exported.
fn is_module_linkage_sensitive_reexport(path: &str) -> bool {
    let parts: Vec<&str> = path.split("::").collect();
    if parts.len() < 2 {
        return false;
    }
    parts[parts.len() - 2] == "iterator" && parts[parts.len() - 1] == "IterEither"
}

fn enum_is_c_like(item: &syn::ItemEnum) -> bool {
    item.generics.params.is_empty()
        && item
            .variants
            .iter()
            .all(|variant| variant.fields.is_empty())
}

fn rewrite_std_io_import(path: &str) -> Option<UseImportAction> {
    // `use std::io;` imports the module name itself; alias it to rusty::io.
    if path == "std::io" {
        return Some(UseImportAction::Raw(
            "namespace io = rusty::io;".to_string(),
        ));
    }

    let io_item = path.strip_prefix("std::io::")?;
    let action = match io_item {
        // Runtime I/O types have direct rusty::io equivalents.
        "Cursor" | "Error" | "Result" | "SeekFrom" | "Stdin" | "Stdout" | "Stderr" => {
            UseImportAction::Using(format!("rusty::io::{}", io_item))
        }
        // Function renames match existing path mapping (`stdin` → `stdin_`, etc.).
        "stdin" => UseImportAction::Using("rusty::io::stdin_".to_string()),
        "stdout" => UseImportAction::Using("rusty::io::stdout_".to_string()),
        "stderr" => UseImportAction::Using("rusty::io::stderr_".to_string()),
        // Read/Write/Seek/BufRead and related trait imports are Rust-only.
        _ => UseImportAction::RustOnly,
    };
    Some(action)
}

fn rewrite_std_panic_import(path: &str) -> Option<UseImportAction> {
    if path == "std::panic" {
        return Some(UseImportAction::Raw(
            "namespace panic = rusty::panic;".to_string(),
        ));
    }

    let item = path.strip_prefix("std::panic::")?;
    let action = match item {
        "AssertUnwindSafe" | "catch_unwind" | "resume_unwind" => {
            UseImportAction::Using(format!("rusty::panic::{}", item))
        }
        _ => UseImportAction::RustOnly,
    };
    Some(action)
}

fn rewrite_std_ptr_import(path: &str) -> Option<UseImportAction> {
    if path == "std::ptr" {
        return Some(UseImportAction::Raw(
            "namespace ptr = rusty::ptr;".to_string(),
        ));
    }

    let item = path.strip_prefix("std::ptr::")?;
    let action = match item {
        "read" | "write" | "copy" | "copy_nonoverlapping" | "drop_in_place" => {
            UseImportAction::Using(format!("rusty::ptr::{}", item))
        }
        "NonNull" => UseImportAction::Using("rusty::ptr::NonNull".to_string()),
        _ => UseImportAction::RustOnly,
    };
    Some(action)
}

fn rewrite_std_mem_import(path: &str) -> Option<UseImportAction> {
    if path == "std::mem" {
        return Some(UseImportAction::Raw(
            "namespace mem = rusty::mem;".to_string(),
        ));
    }

    let item = path.strip_prefix("std::mem::")?;
    let action = match item {
        "drop" => UseImportAction::Using("rusty::mem::drop".to_string()),
        "forget" => UseImportAction::Using("rusty::mem::forget".to_string()),
        "size_of" => UseImportAction::Using("rusty::mem::size_of".to_string()),
        "replace" => UseImportAction::Using("rusty::mem::replace".to_string()),
        "MaybeUninit" => UseImportAction::Using("rusty::MaybeUninit".to_string()),
        "ManuallyDrop" => UseImportAction::Using("rusty::mem::ManuallyDrop".to_string()),
        _ => UseImportAction::RustOnly,
    };
    Some(action)
}

